// Read config from environment variables (set in docker-compose / .env)
const baseUrl = (env.get('RTLS_BASE_URL') || 'https://rtls.ubudu.com/api').replace(/\/+$/, '');
const namespace = env.get('RTLS_NAMESPACE');
const apiKey = env.get('RTLS_API_KEY');

if (!namespace || !apiKey) {
    node.error('RTLS_NAMESPACE and RTLS_API_KEY must be set as environment variables', msg);
    node.status({ fill: 'red', shape: 'ring', text: 'missing RTLS_NAMESPACE / RTLS_API_KEY' });
    return null;
}

node.status({ fill: 'blue', shape: 'dot', text: 'polling…' });

// GET {baseUrl}/cache/{namespace}/positions  with X-API-Key header
msg.method = 'GET';
msg.url = `${baseUrl}/cache/${encodeURIComponent(namespace)}/positions`;
msg.headers = {
    'X-API-Key': apiKey,
    'Accept': 'application/json'
};
return msg;

// The cache endpoint returns an array of CachedAssetPosition objects.
// Each entry carries the tag id (user_udid / MAC), a display name and an
// embedded `zone` object ({ id, name, color }). A tag is considered outside
// any zone when the zone is missing, has no name, or the live API reports the
// sentinel zone name 'OUTSIDE_ALL_ZONES' — all of which we normalize to one
// consistent label.

const OUTSIDE_LABEL = '— outside any zone —';
const OUTSIDE_SENTINELS = ['OUTSIDE_ALL_ZONES', 'OUTSIDE_ALL_ZONE'];

const statusCode = msg.statusCode || 200;
if (statusCode < 200 || statusCode >= 300) {
    node.error('RTLS API returned HTTP ' + statusCode, msg);
    node.status({ fill: 'red', shape: 'ring', text: 'HTTP ' + statusCode });
    return null;
}

let positions = msg.payload;
if (!Array.isArray(positions)) {
    // Some deployments wrap the array; try common shapes, else treat as empty.
    positions = (positions && (positions.data || positions.positions)) || [];
}

const nowMs = Date.now();
const rows = positions.map((p) => {
    const zone = p.zone || null;
    const rawName = zone && zone.name ? String(zone.name) : null;
    const isOutside = !rawName || OUTSIDE_SENTINELS.includes(rawName.toUpperCase());
    const tsMs = p.timestamp ? Date.parse(p.timestamp) : null;
    return {
        tag: p.user_udid || p.external_id || '(unknown)',
        name: p.user_name || p.external_id || p.user_udid || '(unnamed)',
        zone: isOutside ? OUTSIDE_LABEL : rawName,
        inZone: !isOutside,
        zoneId: !isOutside && zone ? zone.id : null,
        zoneColor: !isOutside && zone && zone.color ? zone.color : '#9e9e9e',
        lat: typeof p.lat === 'number' ? Number(p.lat.toFixed(6)) : null,
        lon: typeof p.lon === 'number' ? Number(p.lon.toFixed(6)) : null,
        mapUuid: p.map_uuid || null,
        lastSeen: p.timestamp || null,
        ageSeconds: tsMs ? Math.round((nowMs - tsMs) / 1000) : null
    };
});

// Sort by zone then name for a stable, readable table.
rows.sort((a, b) => (a.zone || '').localeCompare(b.zone || '') || (a.name || '').localeCompare(b.name || ''));

// Group by zone for the debug summary and MQTT payloads.
const byZone = {};
for (const r of rows) {
    (byZone[r.zone] = byZone[r.zone] || []).push(r.name);
}

// Per-zone counts (descending) for the dashboard summary card. The
// 'outside any zone' bucket is always sorted last regardless of size.
const zoneSummary = Object.keys(byZone).map((z) => ({ zone: z, count: byZone[z].length }));
zoneSummary.sort((a, b) => {
    const ao = a.zone === OUTSIDE_LABEL ? 1 : 0;
    const bo = b.zone === OUTSIDE_LABEL ? 1 : 0;
    return (ao - bo) || (b.count - a.count) || a.zone.localeCompare(b.zone);
});

node.status({ fill: 'green', shape: 'dot', text: rows.length + ' tags / ' + zoneSummary.length + ' zones @ ' + new Date(nowMs).toLocaleTimeString() });

// Keep the latest snapshot available for the /tags HTTP endpoint.
const snapshot = { updatedAt: new Date(nowMs).toISOString(), count: rows.length, zoneCount: zoneSummary.length, tags: rows, byZone: byZone, zoneSummary: zoneSummary };
flow.set('latestSnapshot', snapshot);

msg.payload = rows;
msg.snapshot = snapshot;
msg.byZone = byZone;
msg.zoneSummary = zoneSummary;
return msg;

// Emit a clean, human-readable summary to the debug sidebar + container logs.
const rows = msg.payload || [];
const lines = rows.map((r) => `tag ${r.name} (${r.tag}) is in: ${r.zone}`);
const text = lines.length ? lines.join('\n') : 'no tags reported';
node.warn(text); // node.warn shows in debug sidebar AND container stdout
msg.payload = text;
return msg;

// Fed by two sources:
//   - the poll (msg.payload = array of tag rows) -> cache the rows
//   - the filter box (msg.topic = 'filter', msg.payload = search term)
// Either trigger re-renders the table with the current rows + current term.

if (msg.topic === 'filter') {
    flow.set('filterTerm', (msg.payload || '').toString().trim().toLowerCase());
} else if (Array.isArray(msg.payload)) {
    flow.set('tableRows', msg.payload);
}

const rows = flow.get('tableRows') || [];
const term = flow.get('filterTerm') || '';

let shown = rows;
if (term) {
    shown = rows.filter((r) =>
        (r.name && r.name.toLowerCase().includes(term)) ||
        (r.tag && r.tag.toLowerCase().includes(term)) ||
        (r.zone && r.zone.toLowerCase().includes(term))
    );
}

node.status({ fill: 'grey', shape: 'dot', text: shown.length + ' / ' + rows.length + (term ? " matching '" + term + "'" : ' shown') });
msg.payload = shown;
return msg;

// Render the per-zone counts produced by 'Map tag → zone'.
msg.payload = (msg.zoneSummary || []).map((z) => ({ zone: z.zone, tags: z.count }));
return msg;

// Only emit MQTT messages when MQTT_ENABLE=true. Publishes:
//   {base}/snapshot          -> full snapshot (retained)
//   {base}/tag/{tagId}       -> per-tag zone state (retained)
if ((env.get('MQTT_ENABLE') || 'false').toLowerCase() !== 'true') {
    return null;
}

const base = (env.get('MQTT_TOPIC') || 'ubudu/rtls/zones').replace(/\/+$/, '');
const rows = msg.payload || [];
const out = [];

out.push({
    topic: base + '/snapshot',
    retain: true,
    payload: msg.snapshot
});

for (const r of rows) {
    out.push({
        topic: base + '/tag/' + r.tag,
        retain: true,
        payload: r
    });
}

return [out];

const snapshot = flow.get('latestSnapshot');
if (!snapshot) {
    msg.statusCode = 503;
    msg.payload = { error: 'No data yet — the first poll has not completed.' };
    return msg;
}
msg.statusCode = 200;
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = snapshot;
return msg;
